import{_ as a,c as n,a as i,o as e}from"./app-CEcM0piI.js";const p={};function l(t,s){return e(),n("div",null,s[0]||(s[0]=[i(`<p>目前，小程序中已经支持使用npm安装第三方包，从而来提高小程序的开发效率。但是，在小程序中使用</p><p>npm 包有如下 3 个限制:</p><ol><li>不支持依赖于 Node.js 内置库的包</li><li>不支持依赖于浏览器内置对象的包</li><li>不支持依赖于C++插件的包</li></ol><p>使用npm包还要将style:v2新版样式取消,因为新版样式添加了很多样式可能会导致样式混乱</p><h1 id="vant" tabindex="-1"><a class="header-anchor" href="#vant"><span>vant</span></a></h1><p>vant是一个组件库,导入好后可以像正常的组件一样使用</p><h2 id="自定义属性" tabindex="-1"><a class="header-anchor" href="#自定义属性"><span>自定义属性</span></a></h2><p>声明一个自定义属性，属性名需要以两个减号（--）开始，属性值则可以是任何有效的CSS值。和其他属性一样，自定义属性也是写在规则集之内的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>element{</span></span>
<span class="line"><span>	--main-bg-color:brown;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>规则集所指定的选择器定义了自定义属性的可见作用域。通常的最佳实践是定义在根伪类 在使用局部变量时传入到var函数中即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>element {</span></span>
<span class="line"><span>	background-color::var（--main-bg-color);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="api-promise化" tabindex="-1"><a class="header-anchor" href="#api-promise化"><span>api promise化</span></a></h1><p>在小程序中，实现APl Promise 化主要依赖于miniprogram-api-promise这个第三方的npm 包。</p><h1 id="全局数据共享" tabindex="-1"><a class="header-anchor" href="#全局数据共享"><span>全局数据共享</span></a></h1><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import {observable，action} from &#39;mobx-miniprogram&#39;</span></span>
<span class="line"><span>export const store=observable（{</span></span>
<span class="line"><span>	//数据字段</span></span>
<span class="line"><span>	numA:1,</span></span>
<span class="line"><span>	numB:2,</span></span>
<span class="line"><span>	//计算属性</span></span>
<span class="line"><span>	geksum(){</span></span>
<span class="line"><span>		return this.numA + this.numB</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	//actions方法，用来修改store中的数据</span></span>
<span class="line"><span>	updateNum1:action（function（step）{</span></span>
<span class="line"><span>		this.numA += step</span></span>
<span class="line"><span>	}),</span></span>
<span class="line"><span>	updateNum2:action（function（step){</span></span>
<span class="line"><span>		this.numB += step</span></span>
<span class="line"><span>	}),</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="分包" tabindex="-1"><a class="header-anchor" href="#分包"><span>分包</span></a></h1><p>分包指的是把一个完整的小程序项目，按照需求划分为不同的子包，在构建时打包成不同的分包，用户在使用时按需进行加载</p><p>可以优化小程序首次启动的下载时间 在多团队共同开发时可以更好的解耦协作</p><p>分包前，小程序项目中所有的页面和资源都被打包到了一起，导致整个项目体积过大，影响小程序首次启动的下载时间。</p><p>分包后，小程序项目由1个主包+多个分包组成：</p><ul><li>主包：一般只包含项目的启动页面或TabBar页面、以及所有分包都需要用到的一些公共资源</li><li>分包：只包含和当前分包有关的页面和私有资源</li></ul><p>在小程序启动时，默认会下载主包并启动主包内页面 tabBar页面需要放到主包中</p><p>当用户进入分包内某个页面时，客户端会把对应分包下载下来，下载完成后再进行展示 非tabBar页面可以按照功能的不同，划分为不同的分包之后，进行按需下载</p><p><strong>分包的限制</strong> 整个小程序所有分包大小不超过16M（主包+所有分包） 单个分包/主包大小不能超过2M</p><h3 id="分包结构" tabindex="-1"><a class="header-anchor" href="#分包结构"><span>分包结构</span></a></h3><p>分包后主包放到pages文件夹中 其他的分包在根目录中和pages结构相同,和pages属于同一级</p><p>此外还需要在app.json中声明分包的结构</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	&quot;pages&quot;：[</span><span>    //主包的所有页面</span></span>
<span class="line"><span>		&quot;pages/index&quot;,</span></span>
<span class="line"><span>		&quot;pages/logs&quot;</span></span>
<span class="line"><span>	],</span></span>
<span class="line"><span>	“subpackages&quot;：[    //通过subpackages节点，声明分包的结构</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			&quot;root&quot;：“packageA&quot;，</span><span>    //第一个分包的根目录</span></span>
<span class="line"><span>			&quot;pages&quot;：[</span><span>    //当前分包下，所有页面的相对存放路径</span></span>
<span class="line"><span>				&quot;pages/cat&quot;,</span></span>
<span class="line"><span>				&quot;pages/dog&quot;</span></span>
<span class="line"><span>			]</span></span>
<span class="line"><span>		},{</span></span>
<span class="line"><span>			&quot;root&quot;：“packageB&quot;，</span><span>    //第二个分包的根目录</span></span>
<span class="line"><span>			&quot;name&quot;:“pack2&quot;,</span><span>    //分包的别名</span></span>
<span class="line"><span>			“pages&quot;：[    //当前分包下，所有页面的相对存放路径</span></span>
<span class="line"><span>				&quot;pages/apple&quot;,</span></span>
<span class="line"><span>				&quot;pages/banana&quot;</span></span>
<span class="line"><span>			]</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><ol><li>小程序会按subpackages的配置进行分包，subpackages之外的目录将被打包到主包中</li><li>主包也可以有自己的pages（即最外层的pages 字段）</li><li>tabBar页面必须在主包内</li><li>分包之间不能互相嵌套</li></ol><ul><li>主包无法引用分包内的私有资源</li><li>分包之间不能相互引用私有资源</li><li>分包可以引用主包内的公共资源</li></ul><h3 id="独立分包" tabindex="-1"><a class="header-anchor" href="#独立分包"><span>独立分包</span></a></h3><p>开发者可以按需，将某些具有一定功能独立性的页面配置到独立分包中。原因如下：</p><ul><li>当小程序从普通的分包页面启动时，需要首先下载主包</li><li>而独立分包不依赖主包即可运行，可以很大程度上提升分包页面的启动速度</li></ul><p>一个小程序中可以有多个独立分包</p><p>要设置独立分包只需要在app.json中的分包设置中将独立分包的independent设为true即可</p><p>独立分包和普通分包以及主包之间，是相互隔绝的，不能相互引用彼此的资源！</p><h2 id="分包预下载" tabindex="-1"><a class="header-anchor" href="#分包预下载"><span>分包预下载</span></a></h2><p>分包预下载指的是：在进入小程序的某个页面时，由框架自动预下载可能需要的分包，从而提升进入后续分包页面时的启动速度。</p><p>分包预下载需要在app.json中设置preloadRule预下载规则</p><ul><li>path指出进入该页面时要预下载</li><li>packages指出要预下载的包名</li><li>network指定网络设置,all表示任何网络都预下载,wifi表示在wifi环境下才预下载</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&quot;preloadRule&quot;:{</span></span>
<span class="line"><span>	&quot;path&quot;:{</span></span>
<span class="line"><span>		&quot;packages&quot;:[</span></span>
<span class="line"><span>			p1</span></span>
<span class="line"><span>		]</span></span>
<span class="line"><span>		&quot;network&quot;:&quot;all&quot;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同一个分包中的页面享有共同的预下载大小限额2M</p>`,42)]))}const c=a(p,[["render",l]]),r=JSON.parse('{"path":"/front/mini-program/4/","title":"4 npm包","lang":"zh-CN","frontmatter":{"title":"4 npm包","createTime":"2025/06/22 10:03:36","permalink":"/front/mini-program/4/"},"readingTime":{"minutes":4.39,"words":1318},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/微信小程序/4 npm包.md","headers":[]}');export{c as comp,r as data};
